fragmentShader:
#version 460
layout(location = 0) in vec3 vWorldPos;
layout(location = 1) in vec3 vNormal;
layout(location = 2) in vec2 vUV;
layout(location = 0) out vec4 outColor;

layout(set = 0, binding = 0) uniform SceneUBO {
    mat4 viewProj;
    vec3 cameraPosition;
} scene;

layout(set = 0, binding = 1) uniform sampler2D albedoMap;
layout(set = 0, binding = 2) uniform sampler2D metallicRoughnessMap;

layout(set = 0, binding = 3) uniform MaterialUBO {
    vec3 albedoTint;
    float metallic;
    float roughness;
    float ao;
    vec3 lightDirection;
    float lightIntensity;
    int debugMode;
} materialData;

float distributionGGX(vec3 N, vec3 H, float roughness)
{
    float a = roughness * roughness;
    float a2 = a * a;
    float NdotH = max(dot(N, H), 0.0);
    float NdotH2 = NdotH * NdotH;
    float denom = NdotH2 * (a2 - 1.0) + 1.0;
    return a2 / max(3.14159 * denom * denom, 0.0001);
}

void main()
{
    vec3 albedo = texture(albedoMap, vUV).rgb * materialData.albedoTint;
    vec2 mr = texture(metallicRoughnessMap, vUV).bg;
    float roughness = clamp(mr.x * materialData.roughness, 0.04, 1.0);
    float metallic = clamp(mr.y * materialData.metallic, 0.0, 1.0);
    vec3 N = normalize(vNormal);
    vec3 V = normalize(scene.cameraPosition - vWorldPos);
    vec3 L = normalize(-materialData.lightDirection);
    vec3 H = normalize(V + L);

    float NDF = distributionGGX(N, H, roughness);
    vec3 F0 = mix(vec3(0.04), albedo, metallic);
    vec3 specular = F0 * NDF;
    vec3 diffuse = (1.0 - metallic) * albedo / 3.14159;
    float NdotL = max(dot(N, L), 0.0);
    vec3 lighting = (diffuse + specular) * NdotL * materialData.lightIntensity * materialData.ao;

    if (materialData.debugMode == 1) {
        outColor = vec4(albedo, 1.0);
    } else if (materialData.debugMode == 2) {
        outColor = vec4(N * 0.5 + 0.5, 1.0);
    } else if (materialData.debugMode == 3) {
        outColor = vec4(vec3(roughness), 1.0);
    } else if (materialData.debugMode == 4) {
        outColor = vec4(F0, 1.0);
    } else {
        outColor = vec4(lighting, 1.0);
    }
}

