fragmentShader:
#version 460
layout(location = 0) in vec2 vUV;
layout(location = 0) out vec4 outColor;

layout(set = 0, binding = 0) uniform sampler2D sceneColor;
layout(set = 0, binding = 1) uniform sampler2D blurColor;

layout(set = 0, binding = 2) uniform BloomUBO {
    float threshold;
    float knee;
    float intensity;
    float blend;
    int debugMode;
} bloomData;

float extractBright(vec3 color)
{
    float brightness = max(max(color.r, color.g), color.b);
    float soft = clamp((brightness - bloomData.threshold + bloomData.knee) / max(bloomData.knee, 0.0001), 0.0, 1.0);
    return max(brightness - bloomData.threshold, 0.0) * soft;
}

void main()
{
    vec3 scene = texture(sceneColor, vUV).rgb;
    vec3 blurred = texture(blurColor, vUV).rgb;
    float brightMask = extractBright(scene);
    vec3 bloom = blurred * brightMask * bloomData.intensity;
    vec3 combined = mix(scene, scene + bloom, bloomData.blend);

    if (bloomData.debugMode == 1) {
        outColor = vec4(scene, 1.0);
    } else if (bloomData.debugMode == 2) {
        outColor = vec4(vec3(brightMask), 1.0);
    } else if (bloomData.debugMode == 3) {
        outColor = vec4(bloom, 1.0);
    } else {
        outColor = vec4(combined, 1.0);
    }
}

