layout(push_constant) uniform ObjectPush {
    mat4 model;
} objectData;

layout(location = 0) out vec3 vWorldPos;
layout(location = 1) out vec2 vUV;
layout(location = 2) out mat3 vTBN;

void main()
{
    vec4 worldPos = objectData.model * vec4(inPosition, 1.0);
    vec3 T = normalize(mat3(objectData.model) * inTangent.xyz);
    vec3 N = normalize(mat3(objectData.model) * inNormal);
    vec3 B = normalize(cross(N, T) * inTangent.w);

    vWorldPos = worldPos.xyz;
    vUV = inUV;
    vTBN = mat3(T, B, N);
    gl_Position = scene.viewProj * worldPos;
}

fragmentShader:
#version 460
layout(location = 0) in vec3 vWorldPos;
layout(location = 1) in vec2 vUV;
layout(location = 2) in mat3 vTBN;
layout(location = 0) out vec4 outColor;

layout(set = 0, binding = 0) uniform SceneUBO {
    mat4 viewProj;
