fragmentShader:
#version 460
layout(location = 0) in vec3 vWorldPos;
layout(location = 1) in vec3 vNormal;
layout(location = 2) in vec2 vUV;
layout(location = 0) out vec4 outColor;

layout(set = 0, binding = 0) uniform SceneUBO {
    mat4 viewProj;
    vec3 cameraPosition;
} scene;

layout(set = 0, binding = 1) uniform sampler2DShadow shadowMap;
layout(set = 0, binding = 2) uniform ShadowUBO {
    mat4 lightViewProj;
    vec3 lightDirection;
    float bias;
    float normalBias;
    float pcfRadius;
    int debugMode;
} shadowData;

float sampleShadow(vec3 worldPos, vec3 normal)
{
    vec4 lightPos = shadowData.lightViewProj * vec4(worldPos + normal * shadowData.normalBias, 1.0);
    vec3 proj = lightPos.xyz / lightPos.w;
    proj = proj * 0.5 + 0.5;
    return texture(shadowMap, vec3(proj.xy, proj.z - shadowData.bias));
}

void main()
{
    vec3 N = normalize(vNormal);
    vec3 L = normalize(-shadowData.lightDirection);
    float lit = max(dot(N, L), 0.0);
    float shadow = sampleShadow(vWorldPos, N);

    if (shadowData.debugMode == 1) {
        outColor = vec4(vec3(shadow), 1.0);
    } else {
        outColor = vec4(vec3(lit * shadow), 1.0);
    }
}

