fragmentShader:
#version 460
layout(location = 0) in vec2 vUV;
layout(location = 0) out vec4 outColor;

layout(set = 0, binding = 0) uniform NoiseUBO {
    float scale;
    float lacunarity;
    float gain;
    float contrast;
    float time;
    int octaves;
    int debugMode;
    int animate;
} noiseData;

float hash(vec2 p)
{
    return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453123);
}

float noise(vec2 p)
{
    vec2 i = floor(p);
    vec2 f = fract(p);
    float a = hash(i);
    float b = hash(i + vec2(1.0, 0.0));
    float c = hash(i + vec2(0.0, 1.0));
    float d = hash(i + vec2(1.0, 1.0));
    vec2 u = f * f * (3.0 - 2.0 * f);
    return mix(a, b, u.x) + (c - a) * u.y * (1.0 - u.x) + (d - b) * u.x * u.y;
}

float fbm(vec2 p)
{
    float value = 0.0;
    float amplitude = 0.5;
    for (int i = 0; i < noiseData.octaves; ++i) {
        value += amplitude * noise(p);
        p *= noiseData.lacunarity;
        amplitude *= noiseData.gain;
    }
    return value;
}

void main()
{
    vec2 uv = vUV * noiseData.scale;
    if (noiseData.animate == 1) {
        uv.x += noiseData.time * 0.15;
    }
    float base = noise(uv);
    float layered = fbm(uv);
    float contrasted = pow(max(layered, 0.0), noiseData.contrast);

    if (noiseData.debugMode == 1) {
        outColor = vec4(vec3(base), 1.0);
    } else if (noiseData.debugMode == 2) {
        outColor = vec4(vec3(layered), 1.0);
    } else {
        outColor = vec4(vec3(contrasted), 1.0);
    }
}

