#version 460
layout(location = 0) in vec3 inPosition;
layout(location = 1) in vec2 inUV;

layout(set = 0, binding = 0) uniform WaterSceneUBO {
    mat4 viewProj;
    float time;
    float waveAmplitude;
    float waveSpeed;
} waterScene;

layout(location = 0) out vec2 vUV;
layout(location = 1) out float vHeight;

void main()
{
    vec3 position = inPosition;
    position.y += sin(inPosition.x * 2.4 + waterScene.time * waterScene.waveSpeed) * waterScene.waveAmplitude;
    position.y += cos(inPosition.z * 1.8 + waterScene.time * waterScene.waveSpeed * 0.7) * waterScene.waveAmplitude * 0.6;
    vUV = inUV;
    vHeight = position.y;
    gl_Position = waterScene.viewProj * vec4(position, 1.0);
}

fragmentShader:
#version 460
layout(location = 0) in vec2 vUV;
layout(location = 1) in float vHeight;
layout(location = 0) out vec4 outColor;

layout(set = 0, binding = 1) uniform WaterMaterialUBO {
    vec3 shallowColor;
    float foamThreshold;
    vec3 deepColor;
    float foamStrength;
    int debugMode;
} waterMaterial;

void main()
{
    float foam = smoothstep(waterMaterial.foamThreshold, waterMaterial.foamThreshold + 0.08, vHeight) * waterMaterial.foamStrength;
    vec3 waterColor = mix(waterMaterial.deepColor, waterMaterial.shallowColor, clamp(vHeight * 0.5 + 0.5, 0.0, 1.0));
    vec3 finalColor = mix(waterColor, vec3(0.95), foam);

    if (waterMaterial.debugMode == 1) {
        outColor = vec4(vec3(foam), 1.0);
    } else if (waterMaterial.debugMode == 2) {
        outColor = vec4(vec3(vHeight * 0.5 + 0.5), 1.0);
    } else {
        outColor = vec4(finalColor, 1.0);
    }
}

