    float fogFactor = 0.0;

    if (fogData.mode == 0) {
        fogFactor = clamp((distanceToCamera - fogData.fogStart) / max(fogData.fogEnd - fogData.fogStart, 0.001), 0.0, 1.0);
    } else {
        fogFactor = 1.0 - exp(-distanceToCamera * fogData.density);
    }

    vec3 baseColor = vec3(0.62, 0.74, 0.88);
    vec3 finalColor = mix(baseColor, fogData.fogColor, fogFactor);

    if (fogData.debugMode == 1) {
        outColor = vec4(vec3(fogFactor), 1.0);
    } else {
        outColor = vec4(finalColor, 1.0);
    }
}

