fragmentShader:
#version 460
layout(location = 0) in vec2 vUV;
layout(location = 0) out vec4 outColor;

layout(set = 0, binding = 0) uniform RaymarchUBO {
    int maxSteps;
    float surfaceEpsilon;
    float maxDistance;
    int debugMode;
} raymarchData;

float sceneSdf(vec3 p)
{
    float sphere = length(p - vec3(0.0, 0.0, 3.0)) - 1.0;
    float ground = p.y + 1.2;
    return min(sphere, ground);
}

void main()
{
    vec2 uv = vUV * 2.0 - 1.0;
    vec3 ro = vec3(0.0, 0.0, -3.0);
    vec3 rd = normalize(vec3(uv, 1.8));

    float t = 0.0;
    int steps = 0;
    for (steps = 0; steps < raymarchData.maxSteps; ++steps) {
        vec3 p = ro + rd * t;
        float d = sceneSdf(p);
        if (d < raymarchData.surfaceEpsilon) {
            break;
        }
        t += d;
        if (t > raymarchData.maxDistance) {
            break;
        }
    }

    if (raymarchData.debugMode == 1) {
        float heat = float(steps) / float(raymarchData.maxSteps);
        outColor = vec4(heat, 0.2, 1.0 - heat, 1.0);
    } else {
        float shade = 1.0 - float(steps) / float(raymarchData.maxSteps);
        outColor = vec4(vec3(shade), 1.0);
    }
}

