} toonData;

void main()
{
    vec3 N = normalize(vNormal);
    vec3 L = normalize(-toonData.lightDirection);
    vec3 V = normalize(scene.cameraPosition - vWorldPos);
    float lambert = max(dot(N, L), 0.0);
    float toon = floor(lambert * toonData.steps) / max(toonData.steps - 1.0, 1.0);
    float rim = pow(1.0 - max(dot(N, V), 0.0), toonData.rimPower);
    vec3 color = vec3(toon) + toonData.rimColor * rim;

    if (toonData.debugMode == 1) {
        outColor = vec4(vec3(lambert), 1.0);
    } else if (toonData.debugMode == 2) {
        outColor = vec4(vec3(rim), 1.0);
    } else {
        outColor = vec4(color, 1.0);
    }
}

