layout(set = 0, binding = 0) uniform sampler2D sceneColor;
layout(set = 0, binding = 1) uniform PostUBO {
    float intensity;
    int mode;
} postData;

void main()
{
    vec3 color = texture(sceneColor, vUV).rgb;
    vec3 result = color;

    if (postData.mode == 1) {
        float vignette = smoothstep(0.9, 0.2, distance(vUV, vec2(0.5)));
        result *= mix(1.0, vignette, postData.intensity);
    } else if (postData.mode == 2) {
        result = mix(color, vec3(dot(color, vec3(0.299, 0.587, 0.114))), postData.intensity);
    } else if (postData.mode == 3) {
        result.r = texture(sceneColor, vUV + vec2(0.002 * postData.intensity, 0.0)).r;
        result.b = texture(sceneColor, vUV - vec2(0.002 * postData.intensity, 0.0)).b;
    }

    outColor = vec4(result, 1.0);
}

