#version 460
layout(location = 0) in vec2 vUV;
layout(location = 0) out vec4 outColor;

layout(set = 0, binding = 0) uniform sampler2D depthTexture;
layout(set = 0, binding = 1) uniform sampler2D normalTexture;

layout(set = 0, binding = 2) uniform EdgeUBO {
    float depthThreshold;
    float normalThreshold;
    int mode;
} edgeData;

void main()
{
    vec2 texel = 1.0 / vec2(textureSize(depthTexture, 0));
    float centerDepth = texture(depthTexture, vUV).r;
    float rightDepth = texture(depthTexture, vUV + vec2(texel.x, 0.0)).r;
    vec3 centerNormal = texture(normalTexture, vUV).xyz;
    vec3 rightNormal = texture(normalTexture, vUV + vec2(texel.x, 0.0)).xyz;

    float depthEdge = step(edgeData.depthThreshold, abs(centerDepth - rightDepth));
    float normalEdge = step(edgeData.normalThreshold, length(centerNormal - rightNormal));
    float edge = max(depthEdge, normalEdge);

    if (edgeData.mode == 1) {
        outColor = vec4(vec3(centerDepth), 1.0);
    } else if (edgeData.mode == 2) {
        outColor = vec4(centerNormal, 1.0);
    } else {
        outColor = vec4(vec3(edge), 1.0);
    }
}

